$content = Get-Content index.html -Raw; $header = "<script>window.addEventListener('error', function(e) { var err = document.createElement('div'); err.style.cssText = 'position:fixed;top:0;left:0;z-index:9999;background:red;color:white;padding:20px;font-size:20px;width:100%;word-wrap:break-word;'; err.innerHTML = e.message + '<br>' + e.filename + ':' + e.lineno + ':' + e.colno + '<br>' + (e.error ? e.error.stack : ''); document.body.appendChild(err); });</script>"; $content = $header + "`r`n" + $content; Set-Content index.html $content -Encoding UTF8
